func CheckIActivityTaskManagerService(ctx context.Context, sm binder.ServiceManager, name string) (IActivityTaskManager, error) {
	service, err := sm.CheckService(ctx, name)
	if err != nil {
		return nil, err
	}
	return NewIActivityTaskManagerClient(service), nil
}

func WaitIActivityTaskManagerService(ctx context.Context, sm binder.ServiceManager, name string) (IActivityTaskManager, error) {
	service, err := sm.WaitService(ctx, name)
	if err != nil {
		return nil, err
	}
	return NewIActivityTaskManagerClient(service), nil
}

func AddIActivityTaskManagerService(ctx context.Context, sm binder.ServiceManager, name string, impl IActivityTaskManager, opts ...binder.AddServiceOption) error {
	if registrar, ok := sm.(binder.LocalHandlerRegistrar); ok {
		return sm.AddService(ctx, name, NewIActivityTaskManagerHandlerWithRegistrar(registrar, impl), opts...)
	}
	return sm.AddService(ctx, name, NewIActivityTaskManagerHandler(impl), opts...)
}
